def solve(nums: list[int]) -> bool:
    n = len(nums)
    if n < 3:
        return False

    # Precompute the increasing and decreasing segments
    inc = [False] * n
    dec = [False] * n

    # Check increasing from start to each index
    inc[0] = True
    for i in range(1, n):
        if nums[i] > nums[i-1]:
            inc[i] = inc[i-1]
        else:
            inc[i] = False

    # Check decreasing from each index to end
    dec[-1] = True
    for i in range(n-2, -1, -1):
        if nums[i] > nums[i+1]:
            dec[i] = dec[i+1]
        else:
            dec[i] = False

    # Now find p and q such that:
    # 0 < p < q < n-1
    # nums[0..p] is strictly increasing (inc[p] is True)
    # nums[p..q] is strictly decreasing (nums[p] > nums[p+1] > ... > nums[q])
    # nums[q..n-1] is strictly increasing (dec[q] is True)
    # So for p and q to be valid, we need:
    # inc[p] and dec[q] and nums[p] > nums[p+1] and nums[q] < nums[q+1]
    # and p < q and q < n-1

    for p in range(1, n-2):
        if not inc[p]:
            continue
        for q in range(p+1, n-1):
            if not dec[q]:
                continue
            # Check if nums[p..q] is strictly decreasing
            valid = True
            for i in range(p, q):
                if nums[i] <= nums[i+1]:
                    valid = False
                    break
            if valid and nums[q] < nums[q+1]:
                return True
    return False
